import{c as t,Q as a,j as n,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Keep your Claude Code context clean with Subagents — @dani_avila7","description":"","frontmatter":{"title":"Keep your Claude Code context clean with Subagents — @dani_avila7","author":"Daniel San（@dani_avila7）","date":"2026-04-26T00:00:00.000Z","source":"https://x.com/dani_avila7/status/2048486242321662189","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-26-@dani_avila7-662189.md","filePath":"research/tweets/2026-04-26-@dani_avila7-662189.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-04-26-@dani_avila7-662189.md"};function o(l,e,r,h,d,c){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="keep-your-claude-code-context-clean-with-subagents-—-dani-avila7" tabindex="-1">Keep your Claude Code context clean with Subagents — @dani_avila7 <a class="header-anchor" href="#keep-your-claude-code-context-clean-with-subagents-—-dani-avila7" aria-label="Permalink to &quot;Keep your Claude Code context clean with Subagents — @dani_avila7&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/dani_avila7/status/2048486242321662189" target="_blank" rel="noreferrer">https://x.com/dani_avila7/status/2048486242321662189</a><strong>作者</strong>：Daniel San（@dani_avila7） <strong>發布日期</strong>：2026-04-26 <strong>收錄日期</strong>：2026-04-27 <strong>類型</strong>：Twitter Article <strong>統計</strong>：214 likes · 19 retweets · 426 bookmarks · 13974 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Long Claude Code sessions get messy fast. Every grep, find, and ls stays in your context, taking up space you&#39;ll never read again. Subagents fix this: they run work in their own window and return only the result.</p><p>This article goes straight to the point: what subagents are, how to create one, the built-ins that ship with Claude Code, and how to fork the context with CLAUDE_CODE_FORK_SUBAGENT=1</p><h2 id="what-is-a-subagent" tabindex="-1">What is a subagent <a class="header-anchor" href="#what-is-a-subagent" aria-label="Permalink to &quot;What is a subagent&quot;">​</a></h2><p>A subagent is a specialized assistant that runs in its own context window, with its own system prompt, tools, and permissions.</p><p>The main agent calls it, the subagent does the work in isolation, and returns a summary.</p><p>You create one with a Markdown file and frontmatter:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">code-reviewer</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Reviews code for quality, security, and maintainability. Use after writing or modifying code.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Read, Grep, Glob, Bash</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sonnet</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">You are a senior code reviewer. When invoked:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Run git diff to see recent changes</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Focus on modified files</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Start the review immediately</span></span></code></pre></div><p>Claude Code picks it up automatically and invokes it when the description matches the task.</p><h2 id="where-subagents-live" tabindex="-1">Where subagents live <a class="header-anchor" href="#where-subagents-live" aria-label="Permalink to &quot;Where subagents live&quot;">​</a></h2><p>You can save the file in different locations depending on scope. When two subagents share the same name, the higher-priority location wins.</p><p>For most cases you&#39;ll use <code>.claude/agents/</code> (check it into version control, share with your team) or <code>~/.claude/agents/</code> (personal, available everywhere).</p><h2 id="the-problem-one-window-for-everything" tabindex="-1">The problem: one window for everything <a class="header-anchor" href="#the-problem-one-window-for-everything" aria-label="Permalink to &quot;The problem: one window for everything&quot;">​</a></h2><p>Without subagents, the main agent does it all in a single context. You ask it to review a controller, find a pattern, validate something. It fires grep, find, ls, glob, cd, more grep, another find, every call stays in your context.</p><p>Thirty minutes in, you have 80k tokens of noise you&#39;ll never read.</p><p>When Claude compacts the context, that information gets flattened. Important details get lost in the summary.</p><h2 id="built-in-subagents-explore-and-plan" tabindex="-1">Built-in subagents: Explore and Plan <a class="header-anchor" href="#built-in-subagents-explore-and-plan" aria-label="Permalink to &quot;Built-in subagents: Explore and Plan&quot;">​</a></h2><p>Claude Code ships with subagents for the common cases. The two you&#39;ll use most:</p><p><strong>Explore</strong>: searches the codebase without polluting your main context. Fires all the grep and find calls in its own window and returns only the relevant findings.</p><p><strong>Plan</strong>: investigates and produces an implementation plan. Reads files, understands the architecture, and returns a step-by-step doc. Your main context never sees the intermediate reads.</p><p>Instead of 50 tool calls in your window, you get 3 lines with the answer. The rest is discarded.</p><h2 id="forking-the-context" tabindex="-1">Forking the context <a class="header-anchor" href="#forking-the-context" aria-label="Permalink to &quot;Forking the context&quot;">​</a></h2><p>By default, a subagent starts with a blank context. Good for cleanliness, bad when you&#39;ve already invested 100k tokens building understanding of your codebase and you want the subagent to inherit all of it.</p><p>Forking solves that: the subagent starts with an exact copy of the parent&#39;s context at the moment of the fork.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export CLAUDE_CODE_FORK_SUBAGENT=1</span></span></code></pre></div><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Once <code>CLAUDE_CODE_FORK_SUBAGENT=1</code> is set, every subagent spawn inherits the full parent context by default.</p><p>You can also fork on demand with the <code>/fork</code> slash command.</p><p>The fork&#39;s tool calls stay isolated, only its final result lands back in your conversation.</p><p>The forked subagent:</p><ul><li>Inherits the parent&#39;s full conversation at fork time</li><li>Shares the prompt cache prefix with the parent (children 2-N are ~10x cheaper on input tokens)</li><li>Runs in isolation, its tool calls don&#39;t pollute the parent</li><li>Returns only the final summary</li></ul><h2 id="see-it-in-real-time-context-timeline-hook" tabindex="-1">See it in real time: context-timeline hook <a class="header-anchor" href="#see-it-in-real-time-context-timeline-hook" aria-label="Permalink to &quot;See it in real time: context-timeline hook&quot;">​</a></h2><p>Tracking the main agent&#39;s context and the subagents running in parallel is hard to follow from the console. I built a hook to fix this: context-timeline.</p><p>Link: <a href="https://www.aitmpl.com/component/hook/monitoring/context-timeline" target="_blank" rel="noreferrer">https://www.aitmpl.com/component/hook/monitoring/context-timeline</a></p><p>Install:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-code-templates@latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hook</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> monitoring/context-timeline</span></span></code></pre></div><p>What it does: starts the moment you open a session and shows a timeline with the main agent&#39;s context window and how subagents start working in their own separate context.</p><p>Every subagent you have running shows up in real time, along with the context it returns to the main agent when it finishes.</p><p>My recommendation, start with a simple subagent in <code>.claude/agents/</code>. You&#39;ll feel the difference on the first long session.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：用 Subagent 隔離 tool call 雜訊、搭配 CLAUDE_CODE_FORK_SUBAGENT=1 繼承父 context，有效控制 Claude Code 長 session 的 context rot。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>長 session 中每次 grep/find/ls 都留在 context，30 分鐘後累積 80k tokens 雜訊，autocompact 時重要細節遭 flatten 丟失</li><li>Subagent 在獨立 context window 執行工作，只回傳摘要，主 context 不受 tool call 污染</li><li>建立 Subagent 只需一個 Markdown 檔案 + frontmatter（name/description/tools/model），Claude Code 自動偵測並路由</li><li>內建 <code>Explore</code>（codebase 搜尋）與 <code>Plan</code>（架構分析）兩個通用 subagent，50 次 tool call 可壓縮為 3 行答案</li><li><code>CLAUDE_CODE_FORK_SUBAGENT=1</code> 讓 subagent 繼承父 context 完整快照，且 cache prefix 共享（子 2-N 的 input token 成本約降 10x）</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>80k tokens：典型 30 分鐘 session 累積的 tool call 雜訊量</li><li>10x 成本降低：fork subagent 共享 prompt cache prefix 後，子 2-N 的 input token 成本</li><li><code>CLAUDE_CODE_FORK_SUBAGENT=1</code>：env var，全域啟用 context fork</li><li><code>/fork</code>：slash command，按需 fork subagent</li><li><code>context-timeline</code> hook：<a href="https://www.aitmpl.com/component/hook/monitoring/context-timeline" target="_blank" rel="noreferrer">https://www.aitmpl.com/component/hook/monitoring/context-timeline</a> — 視覺化 subagent 並發 context 時間軸</li><li>安裝指令：<code>npx claude-code-templates@latest --hook monitoring/context-timeline</code></li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li><strong>論點支撐充分</strong>：80k tokens 估算具體，10x 成本數字有 prompt caching 機制支撐，context rot 問題符合本 workspace context-management.md 記錄的 300-400k threshold</li><li><strong>值得注意的盲點</strong>：文章假設「blank context subagent」是預設且更乾淨，但 fork 後的 subagent 若攜帶父 context 的 stale 資訊反而可能引入 context rot — 作者僅提及優點，未討論何時不應 fork</li><li><strong>實際應用價值高</strong>：<code>CLAUDE_CODE_FORK_SUBAGENT=1</code> 是新資訊（本 workspace subagent-advanced.md 未記錄此 env var），<code>context-timeline</code> hook 可直接用於 subagent 監控</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9/10</td><td>CLAUDE_CODE_FORK_SUBAGENT=1 可直接加入 subagent-advanced.md；context-timeline hook 可整合進監控策略</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>Fork env var 與 /fork command 是 workspace 未記錄的新資訊；Explore/Plan 內建 subagent 概念已知但有補充細節</td></tr><tr><td>C. 證據品質 (20%)</td><td>7/10</td><td>80k tokens 估算與 10x 成本有機制支撐，但缺乏實測數據；fork cache sharing 是可驗證的 Anthropic 功能</td></tr><tr><td>D. 技術深度 (15%)</td><td>8/10</td><td>提供完整 frontmatter 範例、env var 具體用法、hook 安裝指令，工程師可直接參照實作</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>Subagent context 管理原則跨任何 Claude Code 使用場景通用，不限特定 codebase</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.9/10</strong></td><td>A×0.3+B×0.2+C×0.2+D×0.15+E×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：<code>CLAUDE_CODE_FORK_SUBAGENT=1</code> 與 <code>/fork</code> 是新的操作知識，應更新 <code>.claude/rules/subagent-advanced.md</code>；context-timeline hook 資訊補充進監控策略。</p>`,55)])])}const g=t(s,[["render",o]]);export{u as __pageData,g as default};
